#############################################
## DBsubject()
## DBchapter()
## DBsection()
## Level()
## KEYWORDS()
## TitleText1()
## EditionText1()
## AuthorText1()
## Section1(not reported)
## Problem1(3.5.8.57)
## Author()
## Institution()
## Language(en-US)

DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "parserOneOf.pl",
  "contextFiniteSolutionSets.pl",
  "contextForm.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
do {
  ($m, $n, $q) = random_subset(3,-5..-2,2..5);
  $p = $m*$n + $q;
  ($c, $d) = random_subset(2,1..9);
  $b = -$d - $m*$c + list_random(-3..3,(0)x5);
} until ($p != 0 && $d != 0);
$x = list_random('a'..'n','p'..'z','A'..'D', 'F'..'N','P'..'T','V'..'Z');
Context()->variables->are($x => 'Real');
Context()->noreduce('(-x)+y', '(-x)-y');
$left = Formula("$b + $m($c + $n $x)")->reduce;
$right = Formula("$p $x - ($d + $q $x)")->reduce;
Context("FiniteSolutionSets");
$solution = ($b == -$d - $m*$c)
  ? OneOf(Compute("R"), String("infinitely many solutions"))->cmp(typeMatch => Formula("{1}"))
  : String("no real solutions")->cmp(typeMatch => Formula("{1}"));

############################################################
# Body
############################################################

BEGIN_PGML
Solve the equation for its variable.

[`[$left]=[$right]`]

[_]{$solution}{16}

END_PGML

############################################################
# End Problem
############################################################

ENDDOCUMENT();
